      "content": "const _ = require('lodash');

class ProblemsService {
  constructor(problemRepository) {
    this.problemRepository = problemRepository;
  }

  async listProblems({ limit, difficulty, tags, includeComponents }) {
    // Fetch all problems from repository
    let problems = await this.problemRepository.getAllProblems();

    // Apply filters
    if (difficulty) {
      problems = problems.filter(p => p.difficulty === difficulty);
    }
    if (tags && tags.length > 0) {
      problems = problems.filter(p => tags.every(tag => p.tags.includes(tag)));
    }

    // Apply limit
    if (limit && limit > 0) {
      problems = problems.slice(0, limit);
    }

    // Prepare response
    const response = {
      problems
    };

    if (includeComponents) {
      // Aggregate language totals and status totals for the filtered and limited problems
      const componentLanguageTotals = {};
      const componentStatusTotals = {};

      problems.forEach(problem => {
        if (problem.components && Array.isArray(problem.components)) {
          problem.components.forEach(component => {
            // Language totals
            if (component.language) {
              componentLanguageTotals[component.language] = (componentLanguageTotals[component.language] || 0) + 1;
            }
            // Status totals
            if (component.status) {
              componentStatusTotals[component.status] = (componentStatusTotals[component.status] || 0) + 1;
            }
          });
        }
      });

      response.metadata = {
        componentLanguageTotals,
        componentStatusTotals
      };
    }

    return response;
  }
}

module.exports = ProblemsService;
